41	func TestExecuteReplicateRelaysUpdatesAndDeletesSeparately(t *testing.T) {
42		mainRef := plumbing.NewBranchReferenceName("main")
43		oldRef := plumbing.NewBranchReferenceName("old")
44		oldHash := plumbing.NewHash("1111111111111111111111111111111111111111")
45		newHash := plumbing.NewHash("2222222222222222222222222222222222222222")
46	
47		var gotDesired map[plumbing.ReferenceName]gitproto.DesiredRef
48		var gotHaves map[plumbing.ReferenceName]plumbing.Hash
49		var pushed []gitproto.PushCommand
50		var deleted []gitproto.PushCommand
51	
52		result, err := Execute(context.Background(), Params{
53			SourceService: fakeSourceService{
54				fetchPack: func(_ context.Context, _ *gitproto.Conn, desired map[plumbing.ReferenceName]gitproto.DesiredRef, targetRefs map[plumbing.ReferenceName]plumbing.Hash) (io.ReadCloser, error) {
55					gotDesired = desired
56					gotHaves = targetRefs
57					return io.NopCloser(bytes.NewReader([]byte("PACK"))), nil
58				},
59			},
60			TargetPusher: fakeTargetPusher{
61				pushPack: func(_ context.Context, cmds []gitproto.PushCommand, pack io.ReadCloser) error {
62					defer pack.Close()
63					pushed = append([]gitproto.PushCommand(nil), cmds...)
64					return nil
65				},
66				pushCommands: func(_ context.Context, cmds []gitproto.PushCommand) error {
67					deleted = append([]gitproto.PushCommand(nil), cmds...)
68					return nil
69				},
70			},
71			DesiredRefs: map[plumbing.ReferenceName]planner.DesiredRef{
72				mainRef: {
73					SourceRef:  mainRef,
74					TargetRef:  mainRef,
75					SourceHash: newHash,
76					Kind:       planner.RefKindBranch,
77				},
78			},
79			TargetRefs: map[plumbing.ReferenceName]plumbing.Hash{
80				mainRef: oldHash,
81				oldRef:  oldHash,
82			},
83			PushPlans: []planner.BranchPlan{
84				{
85					SourceRef:  mainRef,
86					TargetRef:  mainRef,
87					SourceHash: newHash,
88					TargetHash: oldHash,
89					Kind:       planner.RefKindBranch,
90					Action:     planner.ActionUpdate,
91				},
92				{
93					TargetRef:  oldRef,
94					TargetHash: oldHash,
95					Kind:       planner.RefKindBranch,
96					Action:     planner.ActionDelete,
97				},
98			},
99		})
100		if err != nil {
101			t.Fatalf("Execute() error = %v", err)
102		}
103		if !result.Relay || result.RelayMode != "replicate" || result.RelayReason != "replicate-overwrite-relay" {
104			t.Fatalf("unexpected result: %+v", result)
105		}
106		if len(gotDesired) != 1 || gotDesired[mainRef].SourceHash != newHash {
107			t.Fatalf("unexpected desired refs: %+v", gotDesired)
108		}
109		if gotHaves[mainRef] != oldHash {
110			t.Fatalf("expected target ref haves, got %+v", gotHaves)
111		}
112		if len(pushed) != 1 || pushed[0].Name != mainRef || pushed[0].New != newHash {
113			t.Fatalf("unexpected pack push commands: %+v", pushed)
114		}
115		if len(deleted) != 1 || !deleted[0].Delete || deleted[0].Name != oldRef {
116			t.Fatalf("unexpected delete commands: %+v", deleted)
117		}
118	}
