372	func newCheckpointPlanner(ctx context.Context, p Params, ref planner.DesiredRef) (*checkpointPlanner, error) {
373		p.log("bootstrap batch fetching commit graph", "branch", ref.TargetRef.String())
374		graphStore := memory.NewStorage()
375		gpRef := gitproto.DesiredRef{SourceRef: ref.SourceRef, TargetRef: ref.TargetRef, SourceHash: ref.SourceHash}
376		if err := p.SourceService.FetchCommitGraph(ctx, graphStore, p.SourceConn, gpRef); err != nil {
377			return nil, fmt.Errorf("fetch bootstrap planning graph for %s: %w", ref.TargetRef, err)
378		}
379		chain, err := planner.FirstParentChain(graphStore, ref.SourceHash)
380		if err != nil {
381			return nil, fmt.Errorf("walk first-parent chain for %s: %w", ref.TargetRef, err)
382		}
383		if len(chain) == 0 {
384			return nil, fmt.Errorf("empty first-parent chain for %s", ref.TargetRef)
385		}
386		return &checkpointPlanner{
387			ctx:        ctx,
388			params:     p,
389			ref:        ref,
390			chain:      chain,
391			probeCache: make(map[string]probeResult),
392			prefetched: make(map[plumbing.Hash][]byte),
393		}, nil
394	}
