396	func (p *checkpointPlanner) plan() ([]plumbing.Hash, map[plumbing.Hash][]byte, error) {
397		checkpoints := make([]plumbing.Hash, 0, len(p.chain))
398		prevIdx := -1
399		prevHash := plumbing.ZeroHash
400		prevSpan := initialCheckpointSpan(p.params.BatchMaxPack, len(p.chain))
401		prevMeasuredBytes := 0
402		for prevIdx < len(p.chain)-1 {
403			bestIdx, err := p.selectNextCheckpoint(prevIdx, prevHash, prevSpan, prevMeasuredBytes)
404			if err != nil {
405				return nil, nil, err
406			}
407			if bestIdx <= prevIdx {
408				return nil, nil, fmt.Errorf("could not find bootstrap checkpoint for %s under batch-max-pack-bytes=%d", p.ref.TargetRef, p.params.BatchMaxPack)
409			}
410			if result, ok := p.cachedProbe(prevHash, bestIdx); ok && !result.tooLarge && len(result.data) > 0 {
411				p.prefetched[p.chain[bestIdx]] = result.data
412				prevSpan = adaptiveNextProbeSpan(p.params.BatchMaxPack, len(result.data), bestIdx-prevIdx, len(p.chain)-1-bestIdx)
413				prevMeasuredBytes = len(result.data)
414			} else {
415				prevSpan = bestIdx - prevIdx
416				prevMeasuredBytes = 0
417			}
418			prevIdx = bestIdx
419			prevHash = p.chain[bestIdx]
420			checkpoints = append(checkpoints, prevHash)
421			p.params.log("bootstrap batch planned checkpoint",
422				"branch", p.ref.TargetRef.String(),
423				"checkpoint", planner.ShortHash(prevHash),
424				"selected", len(checkpoints),
425				"chain_len", len(p.chain))
426		}
427		return checkpoints, p.prefetched, nil
428	}
