430	func (p *checkpointPlanner) selectNextCheckpoint(prevIdx int, prevHash plumbing.Hash, prevSpan int, prevMeasuredBytes int) (int, error) {
431		bestIdx := -1
432		remaining := len(p.chain) - 1 - prevIdx
433		if shouldSelectTipWithoutProbe(p.params.BatchMaxPack, prevMeasuredBytes, prevSpan, remaining) {
434			bestIdx = len(p.chain) - 1
435		} else if shouldProbeTipFirst(p.params.BatchMaxPack, prevMeasuredBytes, prevSpan, remaining) {
436			tipIdx := len(p.chain) - 1
437			tooLarge, err := p.probe(prevHash, tipIdx)
438			if err != nil {
439				return -1, err
440			}
441			if !tooLarge {
442				bestIdx = tipIdx
443			}
444		}
445		if bestIdx != -1 {
446			return bestIdx, nil
447		}
448		return p.searchCheckpointUnderLimit(prevIdx, prevHash, prevSpan)
449	}

449	}
