451	func (p *checkpointPlanner) probe(prevHash plumbing.Hash, idx int) (bool, error) {
452		if result, ok := p.cachedProbe(prevHash, idx); ok {
453			return result.tooLarge, nil
454		}
455		data, tooLarge, err := fetchPackForProbe(p.ctx, p.params, p.ref, p.chain[idx], prevHash, p.params.BatchMaxPack)
456		if err != nil {
457			return false, fmt.Errorf("measure bootstrap batch for %s at %s: %w", p.ref.TargetRef, planner.ShortHash(p.chain[idx]), err)
458		}
459		p.probeCache[probeKey(prevHash, idx)] = probeResult{tooLarge: tooLarge, data: data}
460		return tooLarge, nil
461	}
