468	func (p *checkpointPlanner) probeBounds(prevHash plumbing.Hash, lo, hi int) (largestFit int, smallestTooLarge int) {
469		largestFit = lo - 1
470		smallestTooLarge = hi + 1
471		for idx := lo; idx <= hi; idx++ {
472			result, ok := p.cachedProbe(prevHash, idx)
473			if !ok {
474				continue
475			}
476			if result.tooLarge {
477				if idx < smallestTooLarge {
478					smallestTooLarge = idx
479				}
480				continue
481			}
482			if idx > largestFit {
483				largestFit = idx
484			}
485		}
486		return largestFit, smallestTooLarge
487	}
