643	func fetchPackForProbe(ctx context.Context, p Params, ref planner.DesiredRef, want, have plumbing.Hash, limit int64) ([]byte, bool, error) {
644		desired := singleGP(ref.SourceRef, ref.TargetRef, want)
645		haves := planner.SingleHaveMap(have)
646		packReader, err := p.SourceService.FetchPack(ctx, p.SourceConn, desired, haves)
647		if err != nil {
648			return nil, false, err
649		}
650		defer packReader.Close()
651		data, err := io.ReadAll(gitproto.LimitPackReader(packReader, limit))
652		if err == nil {
653			return data, false, nil
654		}
655		if strings.Contains(err.Error(), "source pack exceeded max-pack-bytes limit") {
656			return nil, true, nil
657		}
658		return nil, false, err
659	}
