78	// Execute runs the bootstrap strategy (one-shot or batched).
79	func Execute(ctx context.Context, p Params, relayReason string) (Result, error) {
80		if p.TargetPusher == nil {
81			return Result{Relay: true, RelayMode: "bootstrap", RelayReason: relayReason}, fmt.Errorf("bootstrap strategy requires TargetPusher")
82		}
83	
84		// GitHub large-repo preflight
85		if batchLimit, ok := githubBatchLimit(ctx, p); ok {
86			p.BatchMaxPack = batchLimit
87			p.log("bootstrap github preflight selected batched mode",
88				"batch_max_pack_bytes", p.BatchMaxPack)
89		}
90	
91		planTargetRefs := p.TargetRefs
92		if p.BatchMaxPack > 0 {
93			planTargetRefs = adjustedBootstrapTargetRefs(p.DesiredRefs, p.TargetRefs)
94		}
95		plans, err := planner.BuildBootstrapPlans(p.DesiredRefs, planTargetRefs)
96		if err != nil {
97			return Result{}, err
98		}
99	
100		result := Result{
101			Plans: plans, Relay: true, RelayMode: "bootstrap", RelayReason: relayReason,
102		}
103	
104		if p.BatchMaxPack > 0 {
105			return executeBatched(ctx, p, plans, result)
106		}
107	
108		// One-shot bootstrap
109		p.log("bootstrap fetching refs from source", "ref_count", len(plans))
110		gpDesired := convert.DesiredRefs(p.DesiredRefs)
111		packReader, err := p.SourceService.FetchPack(ctx, p.SourceConn, gpDesired, nil)
112		if err != nil {
113			if errors.Is(err, git.NoErrAlreadyUpToDate) {
114				return result, nil
115			}
116			return result, fmt.Errorf("fetch source pack: %w", err)
117		}
118		packReader = gitproto.LimitPackReader(packReader, p.MaxPackBytes)
119		packReader = closeOnce(packReader)
120	
121		p.log("bootstrap pushing refs to target", "ref_count", len(plans))
122		cmds := convert.PlansToPushCommands(plans)
123		pushErr := p.TargetPusher.PushPack(ctx, cmds, packReader)
124		_ = packReader.Close()
125		if pushErr != nil {
126			autoBatch, ok := autoBatchMaxPackBytes(p, pushErr)
127			if !ok {
128				return result, fmt.Errorf("push target refs: %w", pushErr)
129			}
130			p.log("bootstrap retrying with batched mode after target rejection",
131				"batch_max_pack_bytes", autoBatch)
132			p.BatchMaxPack = autoBatch
133			return executeBatched(ctx, p, plans, result)
134		}
135	
136		result.Pushed = len(plans)
137		return result, nil
138	}
