160	// --- Batched bootstrap ---
161	
162	func executeBatched(
163		ctx context.Context,
164		p Params,
165		plans []planner.BranchPlan,
166		result Result,
167	) (Result, error) {
168		if !p.SourceService.SupportsBootstrapBatch() {
169			return result, fmt.Errorf("bootstrap batching requires protocol v2 source fetch filter support")
170		}
171	
172		planRefs := make([]planner.DesiredRef, 0, len(plans))
173		tagPlans := make([]planner.BranchPlan, 0, len(plans))
174		tagDesired := make(map[plumbing.ReferenceName]gitproto.DesiredRef)
175		for _, plan := range plans {
176			if plan.Kind == planner.RefKindTag {
177				tagPlans = append(tagPlans, plan)
178				if d, ok := p.DesiredRefs[plan.TargetRef]; ok {
179					tagDesired[plan.TargetRef] = gitproto.DesiredRef{
180						SourceRef: d.SourceRef, TargetRef: d.TargetRef,
181						SourceHash: d.SourceHash, IsTag: true,
182					}
183				}
184				continue
185			}
186			if !plan.SourceRef.IsBranch() || !plan.TargetRef.IsBranch() {
187				return result, fmt.Errorf("bootstrap batching currently supports branch refs and create-only tags")
188			}
189			planRefs = append(planRefs, p.DesiredRefs[plan.TargetRef])
190		}
191	
192		var batches []plannedBatch
193		if len(planRefs) > 0 {
194			p.log("bootstrap batch planning checkpoints", "branch_ref_count", len(planRefs))
195			var err error
196			batches, err = planBatches(ctx, p, planRefs)
197			if err != nil {
198				return result, err
199			}
200		}
201	
202		batchLimit := p.BatchMaxPack
203		if p.MaxPackBytes > 0 && (batchLimit == 0 || p.MaxPackBytes < batchLimit) {
204			batchLimit = p.MaxPackBytes
205		}
206	
207		for _, batch := range batches {
208			result.PlannedBatchCount += len(batch.Checkpoints)
209			result.TempRefs = append(result.TempRefs, batch.TempRef.String())
210			p.log("bootstrap batch branch plan",
211				"branch", batch.Plan.TargetRef.String(),
212				"temp_ref", batch.TempRef.String(),
213				"planned_batches", len(batch.Checkpoints),
214				"resume_hash", planner.ShortHash(batch.ResumeHash))
215	
216			current := batch.ResumeHash
217			startIdx, err := planner.BootstrapResumeIndex(batch.Checkpoints, batch.ResumeHash)
218			if err != nil {
219				return result, fmt.Errorf("resume bootstrap batch for %s: %w", batch.Plan.TargetRef, err)
220			}
221	
222			for idx := startIdx; idx < len(batch.Checkpoints); idx++ {
223				checkpoint := batch.Checkpoints[idx]
224				p.log("bootstrap batch push checkpoint",
225					"branch", batch.Plan.TargetRef.String(),
226					"batch", idx+1,
227					"batch_total", len(batch.Checkpoints),
228					"from", planner.ShortHash(current),
229					"to", planner.ShortHash(checkpoint))
230	
231				stagePlans := []planner.BranchPlan{{
232					Branch: batch.Plan.Branch, SourceRef: batch.Plan.SourceRef,
233					TargetRef: batch.TempRef, SourceHash: checkpoint, TargetHash: current,
234					Kind: batch.Plan.Kind, Action: planner.ActionForTargetHash(current),

235					Reason: fmt.Sprintf("%s -> %s via %s", planner.ShortHash(current), planner.ShortHash(checkpoint), batch.TempRef),
236				}}
237				if idx == len(batch.Checkpoints)-1 {
238					stagePlans = append(stagePlans, planner.BranchPlan{
239						Branch: batch.Plan.Branch, SourceRef: batch.Plan.SourceRef,
240						TargetRef: batch.Plan.TargetRef, SourceHash: checkpoint,
241						TargetHash: plumbing.ZeroHash, Kind: batch.Plan.Kind,
242						Action: planner.ActionCreate,
243						Reason: fmt.Sprintf("create %s at %s", batch.Plan.TargetRef, planner.ShortHash(checkpoint)),
244					})
245				}
246	
247				packReader, err := packReaderForCheckpoint(ctx, p, batch, checkpoint, current, batchLimit)
248				if err != nil {
249					return result, fmt.Errorf("fetch source batch pack for %s: %w", batch.Plan.TargetRef, err)
250				}
251				packReader = closeOnce(packReader)
252				cmds := convert.PlansToPushCommands(stagePlans)
253				if err := p.TargetPusher.PushPack(ctx, cmds, packReader); err != nil {
254					_ = packReader.Close()
255					return result, fmt.Errorf("push bootstrap batch for %s: %w", batch.Plan.TargetRef, err)
256				}
257				_ = packReader.Close()
258				p.log("bootstrap batch checkpoint complete",
259					"branch", batch.Plan.TargetRef.String(),
260					"batch", idx+1,
261					"batch_total", len(batch.Checkpoints))
262				current = checkpoint
263				result.BatchCount++
264			}
265	
266			if current.IsZero() {
267				return result, fmt.Errorf("bootstrap batching for %s completed with no checkpoint state", batch.Plan.TargetRef)
268			}
269			if batch.ResumeHash == batch.Plan.SourceHash && p.TargetRefs[batch.Plan.TargetRef].IsZero() {
270				cmds := []gitproto.PushCommand{{Name: batch.Plan.TargetRef, Old: plumbing.ZeroHash, New: batch.Plan.SourceHash}}
271				if err := p.TargetPusher.PushCommands(ctx, cmds); err != nil {
272					return result, fmt.Errorf("resume bootstrap cutover for %s: %w", batch.Plan.TargetRef, err)
273				}
274			}
275	
276			cmds := []gitproto.PushCommand{{Name: batch.TempRef, Old: current, Delete: true}}
277			if err := p.TargetPusher.PushCommands(ctx, cmds); err != nil {
278				return result, fmt.Errorf("delete bootstrap temp ref for %s: %w", batch.Plan.TargetRef, err)
279			}
280			p.log("bootstrap batch branch finalized", "branch", batch.Plan.TargetRef.String())
281		}
282	
283		// Tag phase (issue #1)
284		if len(tagPlans) > 0 {
285			p.log("bootstrap batch pushing tags after branch batches", "tag_count", len(tagPlans))
286			tagTargetRefs := planner.CopyRefHashMap(p.TargetRefs)
287			for _, batch := range batches {
288				tagTargetRefs[batch.Plan.TargetRef] = batch.Plan.SourceHash
289			}
290			packReader, err := p.SourceService.FetchPack(ctx, p.SourceConn, tagDesired, tagTargetRefs)
291			if err != nil {
292				if errors.Is(err, git.NoErrAlreadyUpToDate) {
293					cmds := convert.PlansToPushCommands(tagPlans)
294					if err := p.TargetPusher.PushCommands(ctx, cmds); err != nil {
295						return result, fmt.Errorf("create tag refs after bootstrap: %w", err)
296					}
297				} else {
298					return result, fmt.Errorf("fetch bootstrap tag pack: %w", err)
299				}
300			} else {
