20	// FirstParentChain walks the first-parent chain from tip back to root,
21	// returning the chain in root-to-tip order.
22	func FirstParentChain(store storer.EncodedObjectStorer, tip plumbing.Hash) ([]plumbing.Hash, error) {
23		commit, err := object.GetCommit(store, tip)
24		if err != nil {
25			return nil, err
26		}
27		chain := make([]plumbing.Hash, 0, 128)
28		for {
29			chain = append(chain, commit.Hash)
30			if len(commit.ParentHashes) == 0 {
31				break
32			}
33			commit, err = object.GetCommit(store, commit.ParentHashes[0])
34			if err != nil {
35				return nil, err
36			}
37		}
38		// Reverse in-place to get root-to-tip order.
39		for i, j := 0, len(chain)-1; i < j; i, j = i+1, j-1 {
40			chain[i], chain[j] = chain[j], chain[i]
