45	// SampledCheckpointCandidates generates a set of candidate indices to probe,
46	// sorted from largest (preferred) to smallest.
47	func SampledCheckpointCandidates(lo, hi int, prevSpan int) []int {
48		if lo > hi {
49			return nil
50		}
51		set := map[int]struct{}{}
52		add := func(idx int) {
53			if idx < lo {
54				idx = lo
55			}
56			if idx > hi {
57				idx = hi
58			}
59			set[idx] = struct{}{}
60		}
61	
62		projected := hi
63		if prevSpan > 0 {
64			projected = lo + prevSpan - 1
65		}
66		add(projected)
67	
68		const sampleCount = 4
69		current := projected
70		for i := 0; i < sampleCount-1; i++ {
71			if current <= lo {
72				add(lo)
73				continue
74			}
75			distance := current - lo
76			current = lo + distance/2
77			add(current)
78		}
79		add(lo)
80	
81		candidates := make([]int, 0, len(set))
82		for idx := range set {
83			candidates = append(candidates, idx)
84		}
85		sort.Sort(sort.Reverse(sort.IntSlice(candidates)))
86		return candidates
87	}
