101		}
102	
103		samples := SampledCheckpointCandidates(lo, hi, prevSpan)
104		best := -1
105		for _, idx := range samples {
106			tooLarge, err := probe(idx)
107			if err != nil {
108				return -1, err
109			}
110			if tooLarge {
111				continue
112			}
113			best = idx
114			break
115		}
116		if best != -1 {
117			return best, nil
118		}
119	
120		if prevSpan > 1 {
