// planCheckpointsFromChain fetches the commit graph (tree:0 filter, one fetch)
// and places checkpoints evenly based on a commit-count estimate of pack size.
//
// This replaces the previous probe-based planner which did a full FetchPack per
// candidate checkpoint to measure actual pack size. That approach was precise
// but impractical for large repos: linux/master (75k commits) required 13+
// fetch-and-discard round-trips just to decide where to split, downloading
// gigabytes of throwaway data before any real push started.
//
// The estimate uses a conservative bytes-per-commit heuristic. If a batch turns
// out larger than the target's limit, the push fails for that batch and the
// caller can retry with a lower --batch-max-pack-bytes. Bootstrap resume
// (via temp refs) ensures already-pushed batches are not re-sent.
func planCheckpointsFromChain(ctx context.Context, p Params, ref planner.DesiredRef) ([]plumbing.Hash, error) {
	p.log("bootstrap batch fetching commit graph", "branch", ref.TargetRef.String())
	graphStore := memory.NewStorage()
	gpRef := gitproto.DesiredRef{SourceRef: ref.SourceRef, TargetRef: ref.TargetRef, SourceHash: ref.SourceHash}
	if err := p.SourceService.FetchCommitGraph(ctx, graphStore, p.SourceConn, gpRef); err != nil {
		return nil, fmt.Errorf("fetch commit graph for %s: %w", ref.TargetRef, err)
	}

	chain, err := planner.FirstParentChain(graphStore, ref.SourceHash)
	if err != nil {
		return nil, fmt.Errorf("walk first-parent chain for %s: %w", ref.TargetRef, err)
	}
	if len(chain) == 0 {
		return nil, fmt.Errorf("empty first-parent chain for %s", ref.TargetRef)
	}

	numBatches := estimateBatchCount(int64(len(chain)), p.BatchMaxPack)
	checkpoints := evenCheckpoints(chain, numBatches)

	p.log("bootstrap batch planned checkpoints",
		"branch", ref.TargetRef.String(),
		"chain_len", len(chain),
		"estimated_batches", numBatches)

	return checkpoints, nil
}

// estimatedBytesPerCommit is the heuristic used to estimate pack size from
// commit count. Real repos vary widely (2–100+ KiB/commit depending on blob
// churn), so this intentionally errs toward more batches (overestimates) rather
// than fewer. If the estimate is too low and a batch exceeds the target's
// receive-pack limit, the push fails and the user can retry with a lower
// --batch-max-pack-bytes; bootstrap resume ensures prior batches aren't re-sent.
const estimatedBytesPerCommit = 8192

func estimateBatchCount(chainLen int64, batchMaxPack int64) int {
	if batchMaxPack <= 0 || chainLen <= 0 {
		return 1
	}
	estimated := chainLen * estimatedBytesPerCommit
	n := int((estimated + batchMaxPack - 1) / batchMaxPack) // ceil division
	if n < 1 {
		n = 1
	}
	return n
}

// evenCheckpoints places numBatches checkpoints evenly along the chain.
// The last checkpoint is always the tip (chain[len-1]).
func evenCheckpoints(chain []plumbing.Hash, numBatches int) []plumbing.Hash {
	if numBatches <= 1 || len(chain) <= 1 {
		return []plumbing.Hash{chain[len(chain)-1]}
	}
	checkpoints := make([]plumbing.Hash, 0, numBatches)
	batchSize := len(chain) / numBatches
	for i := 0; i < numBatches-1; i++ {
		idx := (i+1)*batchSize - 1
		if idx >= len(chain)-1 {
			break
		}
		checkpoints = append(checkpoints, chain[idx])
	}
	checkpoints = append(checkpoints, chain[len(chain)-1])
	return checkpoints
}

